// HasRules applies the HasEdge predicate on the "rules" edge.
func HasRules() predicate.Discount {
	return predicate.Discount(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, RulesTable, RulesColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasRulesWith applies the HasEdge predicate on the "rules" edge with a given conditions (other predicates).
func HasRulesWith(preds ...predicate.DiscountRule) predicate.Discount {
	return predicate.Discount(func(s *sql.Selector) {
		step := newRulesStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasConditions applies the HasEdge predicate on the "conditions" edge.
func HasConditions() predicate.Discount {
	return predicate.Discount(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, ConditionsTable, ConditionsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasConditionsWith applies the HasEdge predicate on the "conditions" edge with a given conditions (other predicates).
func HasConditionsWith(preds ...predicate.DiscountCondition) predicate.Discount {
	return predicate.Discount(func(s *sql.Selector) {
		step := newConditionsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Discount) predicate.Discount {
	return predicate.Discount(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Discount) predicate.Discount {
	return predicate.Discount(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Discount) predicate.Discount {
	return predicate.Discount(sql.NotPredicates(p))
}
